const checkpoints = [];

function norm(str) {
  return (str || '').toString().toLowerCase().trim();
}

const readingLists = JSON.parse(localStorage.getItem('reading_lists') || '[]');
const readingListItems = JSON.parse(localStorage.getItem('reading_list_items') || '[]');
const publications = JSON.parse(localStorage.getItem('publications') || '[]');

// Find target reading list by name (case-insensitive)
const targetList = readingLists.find(rl => norm(rl.name) === norm('Crypto Fraud 2024')) || null;

// Find qualifying cryptocurrency fraud working papers
const qualifyingPubs = publications.filter(p => {
  if (!p || p.publication_type !== 'working_paper') return false;
  if (typeof p.publication_year !== 'number' || p.publication_year < 2021) return false;
  if (typeof p.citation_count !== 'number' || p.citation_count < 50) return false;
  const kws = Array.isArray(p.keywords) ? p.keywords.map(norm) : [];
  const tps = Array.isArray(p.topics) ? p.topics.map(norm) : [];
  const hasCryptoFraudKeyword = kws.some(k => k.includes('cryptocurrency fraud'));
  const hasCryptoAndFraudTopic = tps.includes('cryptocurrency') && tps.includes('fraud');
  return hasCryptoFraudKeyword || hasCryptoAndFraudTopic;
});

// Sort qualifying pubs by publication_date descending and take top 3
const sortedQualifying = [...qualifyingPubs].sort((a, b) => (b.publication_date || '').localeCompare(a.publication_date || ''));
const top3 = sortedQualifying.slice(0, 3).map(p => p.id);

let listPubIds = [];
if (targetList) {
  listPubIds = readingListItems
    .filter(it => it.reading_list_id === targetList.id)
    .map(it => it.publication_id);
}

const qualifyingInList = listPubIds.filter(id => qualifyingPubs.some(p => p.id === id));
const allListPubsAreQualifying = listPubIds.length > 0 && listPubIds.every(id => qualifyingPubs.some(p => p.id === id));
const hasAllTop3 = top3.length === 3 && top3.every(id => listPubIds.includes(id));

// CP1 (0.3): Reading list named 'Crypto Fraud 2024' exists AND contains at least one qualifying publication
checkpoints.push({
  passed: !!targetList && qualifyingInList.length >= 1,
  weight: 0.3
});

// CP2 (0.4): List contains at least 3 qualifying publications AND all publications in the list are qualifying
checkpoints.push({
  passed: !!targetList && qualifyingInList.length >= 3 && listPubIds.length >= 3 && allListPubsAreQualifying,
  weight: 0.4
});

// CP3 (0.3): List includes the 3 most recent qualifying working papers (top 3 by publication_date)
checkpoints.push({
  passed: !!targetList && hasAllTop3,
  weight: 0.3
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

function norm(str) {
  return (str || '').toString().toLowerCase().trim();
}

const datasets = JSON.parse(localStorage.getItem('datasets') || '[]');
const cart = JSON.parse(localStorage.getItem('dataset_cart') || 'null');
const cartItems = JSON.parse(localStorage.getItem('dataset_cart_items') || '[]');

function isCreditCardFraudDataset(d) {
  const kws = Array.isArray(d.keywords) ? d.keywords.map(norm) : [];
  const tps = Array.isArray(d.topics) ? d.topics.map(norm) : [];
  const hasKeyword = kws.some(k => k.includes('credit card fraud'));
  const hasTopic = tps.some(t => t.includes('fraud'));
  return hasKeyword || hasTopic;
}

// All non-commercial credit card fraud micro-transaction datasets
const ccFraudNc = datasets.filter(d => {
  if (!d) return false;
  if (d.data_type !== 'micro_level_transaction_data') return false;
  if (d.license_type !== 'non_commercial_research') return false;
  return isCreditCardFraudDataset(d);
});

// Qualifying datasets with fewer than 50 variables
const compactCcFraud = ccFraudNc.filter(d => typeof d.num_variables === 'number' && d.num_variables < 50);

// Identify the one with the maximum number of observations
let bestDataset = null;
for (const d of compactCcFraud) {
  if (!bestDataset || (d.num_observations || 0) > (bestDataset.num_observations || 0)) {
    bestDataset = d;
  }
}

let cartDatasetIds = [];
if (cart) {
  cartDatasetIds = cartItems
    .filter(it => it.dataset_cart_id === cart.id)
    .map(it => it.dataset_id);
}

const qualifyingInCart = cartDatasetIds.filter(id => compactCcFraud.some(d => d.id === id));

// Datasets in cart that are credit card fraud + non-commercial micro, but NOT compact (>=50 vars)
const nonCompactInCart = cartDatasetIds.filter(id => {
  const d = datasets.find(ds => ds.id === id);
  if (!d) return false;
  const sameDomain = d.data_type === 'micro_level_transaction_data' && d.license_type === 'non_commercial_research' && isCreditCardFraudDataset(d);
  return sameDomain && typeof d.num_variables === 'number' && d.num_variables >= 50;
});

// CP1 (0.4): Dataset cart exists AND contains at least one qualifying compact credit card fraud dataset
checkpoints.push({
  passed: !!cart && qualifyingInCart.length >= 1,
  weight: 0.4
});

// CP2 (0.4): The best (largest by observations) qualifying dataset is in the cart
checkpoints.push({
  passed: !!bestDataset && cartDatasetIds.includes(bestDataset.id),
  weight: 0.4
});

// CP3 (0.2): No non-compact (>=50 vars) credit card fraud non-commercial micro dataset is in the cart
checkpoints.push({
  passed: nonCompactInCart.length === 0,
  weight: 0.2
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

function norm(str) {
  return (str || '').toString().toLowerCase().trim();
}

const lists = JSON.parse(localStorage.getItem('citation_export_lists') || '[]');
const items = JSON.parse(localStorage.getItem('citation_export_items') || '[]');
const publications = JSON.parse(localStorage.getItem('publications') || '[]');

// Qualifying tax evasion journal articles for Latin America, 2015–2022, JIF >= 3
const qualifyingPubs = publications.filter(p => {
  if (!p || p.publication_type !== 'journal_article') return false;
  if (typeof p.publication_year !== 'number' || p.publication_year < 2015 || p.publication_year > 2022) return false;
  const jif = typeof p.journal_impact_factor === 'number' ? p.journal_impact_factor : 0;
  if (jif < 3) return false;
  const topics = Array.isArray(p.topics) ? p.topics.map(norm) : [];
  const regions = Array.isArray(p.regions_covered) ? p.regions_covered.map(norm) : [];
  const hasTaxEvasion = topics.includes('tax evasion');
  const coversLatam = regions.includes('latin_america');
  return hasTaxEvasion && coversLatam;
});

const targetList = lists.find(l => norm(l.name) === norm('Tax Evasion Assignment')) || null;

let listItems = [];
if (targetList) {
  listItems = items.filter(it => it.citation_export_list_id === targetList.id);
}

const qualifyingItems = listItems.filter(it => {
  const isQualPub = qualifyingPubs.some(p => p.id === it.publication_id);
  const style = (it.citation_style || '').toString().toLowerCase();
  const hasText = typeof it.formatted_citation === 'string' && it.formatted_citation.trim().length > 0;
  return isQualPub && style === 'apa' && hasText;
});

const itemsForQualPubs = listItems.filter(it => qualifyingPubs.some(p => p.id === it.publication_id));
const allQualifyingAreApa = itemsForQualPubs.length > 0 && itemsForQualPubs.every(it => (it.citation_style || '').toString().toLowerCase() === 'apa');

// CP1 (0.6): Citation export list named 'Tax Evasion Assignment' exists AND contains at least one APA citation for a qualifying publication
checkpoints.push({
  passed: !!targetList && qualifyingItems.length >= 1,
  weight: 0.6
});

// CP2 (0.4): All citations in this list that refer to qualifying publications use APA style
checkpoints.push({
  passed: !!targetList && itemsForQualPubs.length > 0 && allQualifyingAreApa,
  weight: 0.4
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

function norm(str) {
  return (str || '').toString().toLowerCase().trim();
}

const alerts = JSON.parse(localStorage.getItem('saved_search_alerts') || '[]');
const targetNameNorm = norm('Ponzi Schemes 2010+');

// Alerts with correct name, scope, and Ponzi-related query
const topicAlerts = alerts.filter(a => {
  if (!a) return false;
  const nameOk = norm(a.name) === targetNameNorm;
  const scopeOk = a.search_scope === 'publications';
  const queryOk = norm(a.query || '').includes('ponzi');
  return nameOk && scopeOk && queryOk;
});

// Among those, alerts with correct filters and notification settings
const fullAlerts = topicAlerts.filter(a => {
  const typeOk = a.filters_publication_type === 'working_paper';
  const yearOk = typeof a.filters_year_from === 'number' && a.filters_year_from === 2010;
  const notifTypeOk = a.notification_type === 'in_site';
  const freqOk = a.notification_frequency === 'weekly';
  return typeOk && yearOk && notifTypeOk && freqOk;
});

// CP1 (0.5): At least one alert named 'Ponzi Schemes 2010+' on Ponzi topics in publications scope
checkpoints.push({
  passed: topicAlerts.length > 0,
  weight: 0.5
});

// CP2 (0.5): At least one such alert also has working paper type, year_from=2010, and weekly in-site notifications
checkpoints.push({
  passed: fullAlerts.length > 0,
  weight: 0.5
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

