const checkpoints = [];

function norm(str) {
  return (str || '').toString().toLowerCase().trim();
}

function normName(str) {
  return (str || '').toString().toLowerCase().replace(/\s+/g, ' ').trim().replace(/[\u2013\u2014]/g, '-');
}

const collections = JSON.parse(localStorage.getItem('article_collections') || '[]');
const items = JSON.parse(localStorage.getItem('article_collection_items') || '[]');
const publications = JSON.parse(localStorage.getItem('publications') || '[]');

// Qualifying financial statement fraud detection articles
const qualifyingPubs = publications.filter(p => {
  if (!p || p.publication_type !== 'journal_article') return false;
  if (p.language_code !== 'en') return false;
  if (!p.is_open_access) return false;
  if (!p.has_full_text) return false;
  if (typeof p.publication_year !== 'number' || p.publication_year < 2018 || p.publication_year > 2023) return false;
  const topics = Array.isArray(p.topics) ? p.topics.map(norm) : [];
  const keywords = Array.isArray(p.keywords) ? p.keywords.map(norm) : [];
  const hasFsFraud = topics.includes('financial statement fraud');
  const hasDetection = topics.includes('fraud detection') || keywords.includes('fraud detection');
  return hasFsFraud && hasDetection;
});

const targetNameNorm = normName('FS Fraud Detection 2018–2023');
const targetCollection = collections.find(c => normName(c.name) === targetNameNorm) || null;

let collectionItems = [];
if (targetCollection) {
  collectionItems = items.filter(it => it.article_collection_id === targetCollection.id);
}

const pubIds = collectionItems.map(it => it.publication_id);
const qualifyingInCollection = pubIds.filter(id => qualifyingPubs.some(p => p.id === id));
const allItemsQualifying = collectionItems.length > 0 && collectionItems.every(it => qualifyingPubs.some(p => p.id === it.publication_id));

// CP1 (0.3): Collection named 'FS Fraud Detection 2018–2023' exists and contains at least one qualifying publication
checkpoints.push({
  passed: !!targetCollection && qualifyingInCollection.length >= 1,
  weight: 0.3
});

// CP2 (0.3): Collection contains at least 4 qualifying publications
checkpoints.push({
  passed: !!targetCollection && qualifyingInCollection.length >= 4,
  weight: 0.3
});

// CP3 (0.4): All publications in the collection are qualifying and there are at least 4 items
checkpoints.push({
  passed: !!targetCollection && collectionItems.length >= 4 && allItemsQualifying,
  weight: 0.4
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

function norm(str) {
  return (str || '').toString().toLowerCase().trim();
}

const bookmarks = JSON.parse(localStorage.getItem('bookmarks') || '[]');
const publications = JSON.parse(localStorage.getItem('publications') || '[]');

// Retracted LIBOR manipulation articles
const retractedLiborPubs = publications.filter(p => {
  if (!p || p.publication_status !== 'retracted') return false;
  const titleOk = norm(p.title).includes('libor');
  const kw = Array.isArray(p.keywords) ? p.keywords.map(norm) : [];
  const kwOk = kw.some(k => k.includes('libor manipulation'));
  return titleOk || kwOk;
});

const retractedLiborIds = retractedLiborPubs.map(p => p.id);

const liborBookmarks = bookmarks.filter(b => retractedLiborIds.includes(b.publication_id));
const liborBookmarksWithTag = liborBookmarks.filter(b => {
  const tags = Array.isArray(b.tags) ? b.tags.map(norm) : [];
  return tags.includes('case study');
});

// CP1 (0.4): User bookmarked at least one retracted LIBOR manipulation article
checkpoints.push({
  passed: liborBookmarks.length > 0,
  weight: 0.4
});

// CP2 (0.6): At least one such bookmark includes the tag 'case study'
checkpoints.push({
  passed: liborBookmarksWithTag.length > 0,
  weight: 0.6
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

function norm(str) {
  return (str || '').toString().toLowerCase().trim();
}

const entries = JSON.parse(localStorage.getItem('planner_entries') || '[]');
const events = JSON.parse(localStorage.getItem('events') || '[]');

const startFrom = '2025-09-01T00:00:00Z';
const endTo = '2025-12-31T23:59:59Z';

// Step 1: Upcoming European events in the date window
const step1Events = events.filter(e => {
  if (!e) return false;
  if (e.region !== 'europe') return false;
  if (!e.is_upcoming) return false;
  if (!e.start_date) return false;
  return e.start_date >= startFrom && e.start_date <= endTo;
});

const step1Ids = step1Events.map(e => e.id);

// Step 2: Among these, events on financial crime or fraud with fee <= 500
const step2Events = step1Events.filter(e => {
  const topics = Array.isArray(e.topics) ? e.topics.map(norm) : [];
  const hasFinancialCrime = topics.includes('financial crime');
  const hasFraud = topics.includes('fraud');
  const feeOk = typeof e.registration_fee === 'number' && e.registration_fee <= 500;
  return (hasFinancialCrime || hasFraud) && feeOk;
});

const step2Ids = step2Events.map(e => e.id);

const entriesStep1 = entries.filter(pe => step1Ids.includes(pe.event_id));
const entriesStep2 = entries.filter(pe => step2Ids.includes(pe.event_id));

// CP1 (0.4): Planner contains at least one entry for an upcoming European event in Sept–Dec 2025
checkpoints.push({
  passed: entriesStep1.length > 0,
  weight: 0.4
});

// CP2 (0.6): Planner contains at least one entry for such an event that is on financial crime or fraud and has registration fee <= 500
checkpoints.push({
  passed: entriesStep2.length > 0,
  weight: 0.6
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
